}

export default function CustomAlert({
  variant = "success",
  title = "Default Alert Title",
  description = "This is a default description for the alert. You can customize this text by passing props.",
}: CustomAlertProps) {
  const [visible, setVisible] = useState(true)

  return (
    <AnimatePresence>
